const ACCENTS = ['var(--c0)','var(--c1)','var(--c2)','var(--c3)','var(--c4)'];

// STATE
var activeGroup = 'all';
var sortMode    = 'id';
var query       = '';

// REFS
var searchEl   = document.getElementById('search');
var statsEl    = document.getElementById('stats-count');
var emptyEl    = document.getElementById('empty');
var tabsEl     = document.getElementById('tabs');
var sectionsEl = document.getElementById('sections');

function init() { buildTabs(); buildSections(); render(); }

// BUILD TABS
function buildTabs() {
  var total = DATA.reduce(function(s,g){ return s + g.items.length; }, 0);
  tabsEl.appendChild(makeTab('all', 'All', total, null));
  DATA.forEach(function(g, i) {
    tabsEl.appendChild(makeTab(g.slug, g.name, g.items.length, ACCENTS[i % ACCENTS.length]));
  });
}

function makeTab(slug, label, count, accent) {
  var btn = document.createElement('button');
  btn.className = 'tab' + (slug === 'all' ? ' active' : '');
  btn.dataset.slug = slug;
  if (accent) btn.style.setProperty('--accent', accent);
  var dot = accent ? '<span class="tab-dot" style="color:' + accent + '"></span>' : '';
  btn.innerHTML = dot + '<span>' + label + '</span><span class="tab-count">' + count + '</span>';
  btn.addEventListener('click', function() {
    activeGroup = slug;
    document.querySelectorAll('.tab').forEach(function(t){ t.classList.remove('active'); });
    btn.classList.add('active');
    render();
  });
  return btn;
}

// BUILD SECTIONS
function buildSections() {
  DATA.forEach(function(g, i) {
    var accent = ACCENTS[i % ACCENTS.length];
    var sec = document.createElement('div');
    sec.className = 'group-section';
    sec.id = 'sec-' + g.slug;
    sec.innerHTML =
      '<div class="group-heading">' +
        '<span class="group-label">' + g.name + '</span>' +
        '<span class="group-badge" style="color:' + accent + '">' + g.slug + '</span>' +
        '<span class="group-count" id="cnt-' + g.slug + '"></span>' +
      '</div>' +
      '<div class="cards" id="cards-' + g.slug + '"></div>';
    sectionsEl.appendChild(sec);
  });
}

// RENDER
function render() {
  var q = query.toLowerCase().trim();
  var totalVisible = 0;

  DATA.forEach(function(g, gi) {
    var accent = ACCENTS[gi % ACCENTS.length];
    var sec   = document.getElementById('sec-' + g.slug);
    var grid  = document.getElementById('cards-' + g.slug);
    var cntEl = document.getElementById('cnt-' + g.slug);

    if (activeGroup !== 'all' && activeGroup !== g.slug) { sec.hidden = true; return; }

    var items = g.items.filter(function(item) {
      return !q ||
        item.name.toLowerCase().includes(q) ||
        item.id.includes(q) ||
        item.file.toLowerCase().includes(q);
    });

    if (sortMode === 'name') {
      items = items.slice().sort(function(a,b){ return a.name.localeCompare(b.name); });
    } else {
      items = items.slice().sort(function(a,b){ return parseInt(a.id) - parseInt(b.id); });
    }

    sec.hidden = items.length === 0;
    totalVisible += items.length;
    cntEl.textContent = items.length + ' file' + (items.length !== 1 ? 's' : '');

    grid.innerHTML = '';
    items.forEach(function(item, idx) {
      var a = document.createElement('a');
      a.className = 'card';
      a.href = item.file;
      a.style.cssText = '--card-accent:' + accent + '; animation-delay:' + (idx * 30) + 'ms';
      var hi = q ? item.name.replace(new RegExp(escRe(q), 'gi'), '<mark>$&</mark>') : item.name;
      a.innerHTML =
        '<div class="card-id">' + item.id + '</div>' +
        '<div class="card-body">' +
          '<div class="card-name">' + hi + '</div>' +
          '<div class="card-file">' + item.file + '</div>' +
        '</div>' +
        '<div class="card-arrow">&#x2192;</div>';
      grid.appendChild(a);
    });
  });

  statsEl.textContent = totalVisible;
  emptyEl.style.display = totalVisible === 0 ? 'block' : 'none';
}

function escRe(s) {
  return s.replace(/[-[\]{}()*+?.,\\^$|#\s]/g, '\\$&');
}

// EVENTS
document.querySelectorAll('.sort-btn').forEach(function(btn) {
  btn.addEventListener('click', function() {
    sortMode = btn.dataset.sort;
    document.querySelectorAll('.sort-btn').forEach(function(b){ b.classList.remove('active'); });
    btn.classList.add('active');
    render();
  });
});

searchEl.addEventListener('input', function(e) {
  query = e.target.value;
  render();
});

document.addEventListener('keydown', function(e) {
  if (e.key === '/' && document.activeElement !== searchEl) {
    e.preventDefault(); searchEl.focus();
  }
  if (e.key === 'Escape') searchEl.blur();
});

document.getElementById('footer-date').textContent =
  new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long' });

init();